// tsconfig.json must enable: "experimentalDecorators": true
// or use TC39 stage-3 decorators with "useDefineForClassFields": true

// Simplest class decorator — a function that takes the constructor
function Sealed(target: Function): void {
  Object.seal(target);          // prevent new static properties
  Object.seal(target.prototype); // prevent new instance properties
}

@Sealed
class BankAccount {
  constructor(public owner: string, private balance: number) {}
  deposit(amount: number): void { this.balance += amount; }
}

// BankAccount.newProp = 'x'; // TypeError at runtime — sealed

// Factory — receives options, returns the actual decorator
function Log(prefix: string) {
  return function (target: Function): void {
    console.log(\`[${prefix}] class registered: \${target.name}\`);
  };
}

@Log('APP')
class UserService {}

// Console at module load: [APP] class registered: UserService

// Without a factory, only bare decorators work:
function Singleton(target: Function): void { /* ... */ }
@Singleton
class ConfigService {}

function WithToString(target: Function): void {
  target.prototype.toString = function () {
    return JSON.stringify(this, null, 2);
  };
}

@WithToString
class Product {
  constructor(public name: string, public price: number) {}
}

console.log(String(new Product('Widget', 9.99)));
// {"name": "Widget", "price": 9.99}

type Constructor<T = {}> = new (...args: unknown[]) => T;

function Timestamped<TBase extends Constructor>(Base: TBase) {
  return class extends Base {
    createdAt = new Date().toISOString();
  };
}

@Timestamped
class User {
  constructor(public name: string) {}
}

const u = new User('Alice');
console.log(u.name);      // 'Alice'
console.log((u as any).createdAt); // ISO timestamp

// Requires: import 'reflect-metadata'; (Angular sets this up)
// and tsconfig: "emitDecoratorMetadata": true

const ROLES_KEY = Symbol('roles');

function RequiresRoles(...roles: string[]) {
  return function (target: Function): void {
    Reflect.defineMetadata(ROLES_KEY, roles, target);
  };
}

function getRoles(target: Function): string[] {
  return Reflect.getMetadata(ROLES_KEY, target) ?? [];
}

@RequiresRoles('admin', 'editor')
class AdminDashboard {}

console.log(getRoles(AdminDashboard)); // ['admin', 'editor']

function A(target: Function) { console.log('A applied'); }
function B(target: Function) { console.log('B applied'); }

@A
@B
class Example {}

// Console output (decorators applied bottom-up):
// B applied
// A applied

// Factory order:
function F(label: string) {
  console.log(\`F factory: \${label}\`);
  return (target: Function) => { console.log(\`F applied: \${label}\`); };
}

@F('outer')
@F('inner')
class Demo {}

// F factory: outer  (outer factory called first)
// F factory: inner  (inner factory called second)
// F applied: inner  (inner decorator applied first)
// F applied: outer  (outer decorator applied second)

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly _isLoggedIn = signal(false);
  readonly isLoggedIn = this._isLoggedIn.asReadonly();

  login(): void { this._isLoggedIn.set(true); }
  logout(): void { this._isLoggedIn.set(false); }
}

// Angular's DI reads the decorator metadata and registers AuthService
// automatically — no need to list it in providers: [] of a module

@Component({
  selector: 'app-hello',
  standalone: true,
  template: '<h1>Hello, {{ name }}!</h1>',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HelloComponent {
  @Input() name = 'World';
}

function TrackInstances<T extends { new(...args: unknown[]): {} }>(Base: T) {
  let count = 0;

  return class extends Base {
    static get instanceCount() { return count; }

    constructor(...args: unknown[]) {
      super(...args);
      count++;
    }
  };
}

@TrackInstances
class Widget {
  constructor(public id: string) {}
}

new Widget('a');
new Widget('b');
console.log((Widget as any).instanceCount); // 2

const PERMISSION_KEY = Symbol('permissions');

function Permissions(...perms: string[]) {
  return (target: Function) => {
    Reflect.defineMetadata(PERMISSION_KEY, perms, target);
  };
}

// Angular route guard reads the metadata
@Injectable({ providedIn: 'root' })
class PermissionGuard implements CanActivate {
  constructor(private activatedRoute: ActivatedRoute) {}

  canActivate(route: ActivatedRouteSnapshot): boolean {
    const component = route.component;
    if (!component) return true;
    const required: string[] = Reflect.getMetadata(PERMISSION_KEY, component) ?? [];
    const userPerms: string[] = this.getUserPermissions();
    return required.every(p => userPerms.includes(p));
  }

  private getUserPermissions(): string[] {
    return JSON.parse(localStorage.getItem('perms') ?? '[]');
  }
}

// Decorated component
@Component({ selector: 'app-admin', template: '...', standalone: true })
@Permissions('admin', 'editor')
export class AdminComponent {}

function Mixin(...mixins: object[]) {
  return (target: Function): void => {
    mixins.forEach(mixin => {
      Object.getOwnPropertyNames(mixin).forEach(name => {
        if (name === 'constructor') return;
        Object.defineProperty(
          target.prototype,
          name,
          Object.getOwnPropertyDescriptor(mixin, name) ?? Object.create(null)
        );
      });
    });
  };
}

const Serializable = {
  toJSON(this: object): string { return JSON.stringify(this); },
  toCSV(this: Record<string, unknown>): string {
    return Object.values(this).join(',');
  }
};

const Validatable = {
  validate(this: object): boolean {
    return Object.values(this).every(v => v !== null && v !== undefined);
  }
};

@Mixin(Serializable, Validatable)
class Order {
  constructor(public id: string, public total: number) {}
}

const order = new Order('O1', 99.9);
console.log((order as any).toJSON());     // {"id":"O1","total":99.9}
console.log((order as any).validate());   // true

// TC39 stage-3 class decorator (TypeScript 5.0+)
// tsconfig: no experimentalDecorators needed; uses "useDefineForClassFields": true

function sealed(target: typeof SealedClass, context: ClassDecoratorContext) {
  // context.kind === 'class'
  // context.name === 'SealedClass'
  context.addInitializer(function (this: typeof SealedClass) {
    Object.seal(this);
    Object.seal(this.prototype);
  });
}

@sealed
class SealedClass {
  x = 1;
}

// Legacy vs Modern — key differences:
// Legacy: decorator receives the class constructor directly
//   function MyDec(target: Function): void { ... }
// Modern: decorator receives (value, context) where context has .kind, .name, .addInitializer
//   function MyDec(target: typeof MyClass, ctx: ClassDecoratorContext): void { ... }

// Testing an @Injectable service — TestBed handles the decorator
describe('AuthService', () => {
  let service: AuthService;

  beforeEach(() => {
    TestBed.configureTestingModule({});
    service = TestBed.inject(AuthService);
  });

  it('starts logged out', () => {
    expect(service.isLoggedIn()).toBe(false);
  });

  it('updates isLoggedIn after login()', () => {
    service.login();
    expect(service.isLoggedIn()).toBe(true);
  });
});

// Testing a custom class decorator directly
describe('@Sealed decorator', () => {
  it('prevents adding new properties to the prototype', () => {
    @Sealed
    class Subject {}
    expect(Object.isSealed(Subject.prototype)).toBe(true);
  });
});
